/* BTCard — organism card with three visual variants.
   Figma node 93:157 (no D/M prefix — all platforms).
   Shared between @btech/ui-vue and @btech/ui-react — keep these files identical. */

/* ── Container ──────────────────────────────────────────────────────────── */
.bt-card {
  display: flex;
  flex-direction: column;
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  font-family: var(--typography-font-family-sans);
  box-sizing: border-box;
  width: 100%;
}

/* ── Variant: default ───────────────────────────────────────────────────── */
.bt-card--default {
  border-radius: var(--radius-lg);   /* 16px */
  padding: var(--space-lg);
  gap: var(--space-lg);
}

/* ── Variant: small ─────────────────────────────────────────────────────── */
.bt-card--small {
  border-radius: var(--radius-md);   /* 8px */
  padding: var(--space-md);
  gap: var(--space-md);
}

/* ── Variant: image ─────────────────────────────────────────────────────── */
.bt-card--image {
  border-radius: var(--radius-lg);   /* 16px */
  padding: 0;
  overflow: hidden;
}

/* ── Image element ─────────────────────────────────────────────────────── */
.bt-card__image {
  width: 100%;
  height: 180px;
  object-fit: cover;
  display: block;
  flex-shrink: 0;
}

/* ── Image slot wrapper (custom widget replaces the <img>) ─────────────── */
.bt-card__image-slot {
  width: 100%;
  height: 180px;
  flex-shrink: 0;
  overflow: hidden;   /* belt-and-suspenders; parent already clips */
}

/* ── Content wrapper below the image (padding + gap) ───────────────────── */
.bt-card__image-content {
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
  padding: var(--space-lg);
}

/* ── Header row: [header-block  |  header-aside] ───────────────────────── */
.bt-card__header-row {
  display: flex;
  align-items: flex-start;
  gap: var(--space-lg);
  width: 100%;
}

/* ── Header block: [title-row  /  description] ──────────────────────────── */
.bt-card__header {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  flex: 1;
  min-width: 0;
  overflow: hidden;
}

/* ── Title row: [title text  |  title-action] ───────────────────────────── */
.bt-card__title-row {
  display: flex;
  align-items: flex-start;
  gap: var(--space-xs);
  width: 100%;
}

/* ── Title ──────────────────────────────────────────────────────────────── */
.bt-card__title {
  flex: 1;
  min-width: 0;
  font-size: var(--typography-font-size-md);        /* fontSize.md */
  font-weight: 700;       /* subheading/h6 — bold */
  line-height: var(--typography-line-height-sm);      /* lineHeight.sm */
  letter-spacing: 0;
  color: var(--text-primary);
  word-break: break-word;
}

.bt-card--small .bt-card__title {
  font-size: var(--typography-font-size-sm);        /* fontSize.sm */
  font-weight: 500;       /* body/regular — medium */
  line-height: var(--typography-line-height-xs);      /* lineHeight.xs */
}

/* ── Description ────────────────────────────────────────────────────────── */
.bt-card__description {
  font-size: var(--typography-font-size-sm);        /* fontSize.sm */
  font-weight: 500;       /* body/regular */
  line-height: var(--typography-line-height-xs);      /* lineHeight.xs */
  letter-spacing: 0;
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.bt-card--small .bt-card__description {
  font-size: var(--typography-font-size-xs);        /* fontSize.xs */
}

/* ── Slot containers ────────────────────────────────────────────────────── */
.bt-card__title-action {
  flex-shrink: 0;
  width: 20px;
  align-self: stretch;
}

.bt-card__header-aside {
  flex-shrink: 0;
  align-self: flex-start;
}

/* ── Body ───────────────────────────────────────────────────────────────── */
.bt-card__body {
  width: 100%;
}

/* ── Footer ─────────────────────────────────────────────────────────────── */
.bt-card__footer {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: var(--space-sm);
  width: 100%;
  overflow: hidden;
}

/**
 * BTCard — flexible card organism with three visual variants.
 *
 * Figma: node 93:157 (no D/M prefix — all platforms).
 *
 * @example
 * ```tsx
 * // Default with footer
 * <BTCard title="Order #123" description="Placed 26 May" onCancel={dismiss} onSubmit={confirm}>
 *   <p>Order contents here.</p>
 * </BTCard>
 *
 * // Small (no footer)
 * <BTCard variant="small" title="Summary" description="3 items" />
 *
 * // Image — pass any element via the `image` ReactNode prop
 * <BTCard
 *   variant="image"
 *   title="Title"
 *   description="Desc"
 *   image={<img src="/photo.jpg" style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="Photo" />}
 *   onCancel={dismiss}
 *   onSubmit={confirm}
 * />
 *
 * // Custom image widget (video, shimmer overlay, etc.)
 * <BTCard
 *   variant="image"
 *   title="Title"
 *   image={<video src="/promo.mp4" autoPlay muted loop style={{ width: '100%', height: '100%', objectFit: 'cover' }} />}
 *   onSubmit={confirm}
 * />
 * ```
 */
import * as React from 'react';
import './BTCard.css';
import type { BTCardProps } from './BTCard.types';
import { BTButton } from '../button/BTButton';

const cn = (...parts: Array<string | false | null | undefined>): string =>
  parts.filter(Boolean).join(' ');

export interface BTCardReactProps extends BTCardProps {
  /** Content placed right of the title text (20px wide). Default/Image only. */
  titleAction?: React.ReactNode;
  /** Content placed right of the entire header block (20px wide). Default/Image only. */
  headerAside?: React.ReactNode;
  /** Main body content area (slot3 in Figma). */
  children?: React.ReactNode;
  /**
   * Image for `variant="image"` — any ReactNode (img, video, custom widget, etc.).
   * The card handles clipping; pass your element with `width:100%; height:100%; object-fit:cover`.
   *
   * @example
   * ```tsx
   * image={<img src="/photo.jpg" style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="Photo" />}
   * ```
   */
  image?: React.ReactNode;
  /** Replaces the built-in Cancel + Submit footer entirely. */
  footer?: React.ReactNode;
  /** Fired when the Cancel button is clicked. */
  onCancel?: () => void;
  /** Fired when the Submit button is clicked. */
  onSubmit?: () => void;
  className?: string;
}

export const BTCard = React.forwardRef<HTMLDivElement, BTCardReactProps>(
  function BTCard(
    {
      variant = 'default',
      title,
      description,
      image,
      hasFooter,
      cancelLabel = 'Cancel',
      submitLabel = 'Submit',
      titleAction,
      headerAside,
      children,
      footer,
      onCancel,
      onSubmit,
      className,
    },
    ref,
  ) {
    const showFooter = hasFooter !== undefined ? hasFooter : variant !== 'small';

    const hasHeader =
      title != null || description != null || Boolean(titleAction) || (Boolean(headerAside) && variant !== 'small');

    /** Shared header row — reused in both image and default/small branches. */
    const headerRow = hasHeader ? (
      <div className="bt-card__header-row">
        <div className="bt-card__header">
          {(title != null || titleAction) && (
            <div className="bt-card__title-row">
              {title != null && <p className="bt-card__title">{title}</p>}
              {titleAction && <div className="bt-card__title-action">{titleAction}</div>}
            </div>
          )}
          {description && <p className="bt-card__description">{description}</p>}
        </div>
        {headerAside && variant !== 'small' && (
          <div className="bt-card__header-aside">{headerAside}</div>
        )}
      </div>
    ) : null;

    const bodySlot = children ? <div className="bt-card__body">{children}</div> : null;

    const footerSlot = showFooter
      ? footer ?? (
          <div className="bt-card__footer">
            <BTButton label={cancelLabel} variant="secondary-light" size="small" onClick={onCancel} />
            <BTButton label={submitLabel} variant="primary" size="small" onClick={onSubmit} />
          </div>
        )
      : null;

    return (
      <div ref={ref} className={cn(`bt-card bt-card--${variant}`, className)}>
        {variant === 'image' ? (
          <>
            {image && <div className="bt-card__image-slot">{image}</div>}
            <div className="bt-card__image-content">
              {headerRow}
              {bodySlot}
              {footerSlot}
            </div>
          </>
        ) : (
          <>
            {headerRow}
            {bodySlot}
            {footerSlot}
          </>
        )}
      </div>
    );
  },
);

BTCard.displayName = 'BTCard';

/**
 * BTCard — type definitions.
 *
 * A flexible card organism with three visual variants:
 * - `default` — full card with title, description, optional body, optional footer.
 * - `small`   — compact card with title + description only (no footer).
 * - `image`   — card with a top image, then same structure as default.
 *
 * Figma: node 93:157 (no D/M prefix — all platforms).
 */

/** Visual variant of the card. */
export type BTCardVariant = 'default' | 'small' | 'image';

export interface BTCardProps {
  /** Visual variant. @default 'default' */
  variant?: BTCardVariant;
  /** Card title — bold at the top. */
  title: string;
  /** Supporting description shown below the title. */
  description?: string;
  /**
   * Show the cancel + submit footer.
   * Defaults to `true` for `default` and `image`, `false` for `small`.
   */
  hasFooter?: boolean;
  /** Label for the cancel button. @default 'Cancel' */
  cancelLabel?: string;
  /** Label for the submit button. @default 'Submit' */
  submitLabel?: string;
}
// Image for variant="image" is passed via the `image` ReactNode prop on BTCardReactProps:
//
// ```tsx
// <BTCard
//   variant="image"
//   title="Title"
//   image={<img src="/photo.jpg" style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="Photo" />}
// />
// ```

export { BTCard } from './BTCard';
export type { BTCardReactProps } from './BTCard';
export type { BTCardProps, BTCardVariant } from './BTCard.types';
